import { format } from 'date-fns'

export const StudentColumns = [
    {
        Header: 'ID',
        Footer: 'ID',
        accessor: 'id',
        disableFilters: true
    },
    {
        Header: 'Student ID',
        Footer: 'Student ID',
        accessor: 'studentID'
    },
    {
        Header: 'First Name',
        Footer: 'First Name',
        accessor: 'firstName'
    },
    {
        Header: 'Middle Name',
        Footer: 'Middle Name',
        accessor: 'middleName'
    },
    {
        Header: 'Last Name',
        Footer: 'Last Name',
        accessor: 'lastName'
    },
    {
        Header: 'Password',
        Footer: 'Password',
        accessor: 'password'
    },
    {
        Header: 'Date Created',
        Footer: 'Date Created',
        accessor: 'dateCreated',
        Cell: ({ value }) => {return format(new Date(value), 'dd/MM/yyyy')}
    }
]
